# --- plot helper (hidden) — vertical launches at three speeds ---
import math as __m
def __launch(v0, dt, steps, every):
    G = 6.674e-11; M = 5.972e24; r0 = 6.371e6
    r = r0; v = v0; t = 0.0
    pts = [[0.0, 0.0]]
    for i in range(steps):
        a = -G * M / (r * r)
        v += a * dt; r += v * dt; t += dt
        if r < r0:
            pts.append([round(t, 1), 0.0]); break
        if i % every == 0:
            pts.append([round(t, 1), round(r - r0, 1)])
    return pts

def __plot(_):
    return [
        {"name": "too slow (9000) — falls back", "points": __launch(9000, 5.0, 4000, 20), "highlight": False},
        {"name": "escape speed (11186) — climbs forever", "points": __launch(11186, 5.0, 4000, 20), "highlight": True},
        {"name": "fast (13000) — long gone", "points": __launch(13000, 5.0, 4000, 20), "highlight": False},
    ]
